+                    args += [ "-d3d" ]
+                } else if (IS_MAC) {
+                    args += [ "-mtl" ]
+                }
+                if (IS_LINUX | IS_INCLUDE_ES2) {
+                    args += [ "-es2" ]
+                }
+                args += ["-name", "$file"]
